        cmin, cmax = int(cols.min()), int(cols.max())
        sub = np.zeros((rmax-rmin+1, cmax-cmin+1), dtype=int)
        for r, cc in zip(rows.tolist(), cols.tolist()):
            sub[r-rmin, cc-cmin] = int(grid[r, cc])
        shapes[c] = sub

    total_pixels = sum(int(np.count_nonzero(shapes[c])) for c in colors)
    other_colors = [c for c in colors if c != five_color]

    # Find pure rotation of 5-shape with 5 at (0,0)
    tl_shape = None
    for k in range(4):
        r = np.rot90(shapes[five_color], k)
        pos = np.where(r == 5)
        if len(pos[0]) > 0 and int(pos[0][0]) == 0 and int(pos[1][0]) == 0:
            tl_shape = r.copy()
            break

    if tl_shape is None:
        return [[0]]

    h_tl, w_tl = tl_shape.shape

    # Precompute pure rotations for other shapes
    rotations = {}
    for c in other_colors:
        rots = []
        seen = set()
        for k in range(4):
            r = np.rot90(shapes[c], k)
            key = r.tobytes()
            if key not in seen:
                seen.add(key)
                rots.append(r)
        rotations[c] = rots

    # Search for valid tiling
    for perm in permutations(other_colors):
        tr_c, bl_c, br_c = perm

        for tr_shape in rotations[tr_c]:
            h_tr, w_tr = tr_shape.shape
            for bl_shape in rotations[bl_c]:
                h_bl, w_bl = bl_shape.shape
                for br_shape in rotations[br_c]:
                    h_br, w_br = br_shape.shape

                    min_H = max(h_tl, h_tr, h_bl, h_br)
                    min_W = max(w_tl, w_tr, w_bl, w_br)

                    for out_H in range(min_H, total_pixels + 1):
                        if total_pixels % out_H != 0:
                            continue
                        out_W = total_pixels // out_H
                        if out_W < min_W or out_H > total_pixels:
                            continue
                        if out_W < w_tr or out_W < w_bl or out_W < w_br:
                            continue
                        if out_H < h_tr or out_H < h_bl or out_H < h_br:
                            continue

                        placements = [
                            (tl_shape, 0, 0),
                            (tr_shape, 0, out_W - w_tr),
                            (bl_shape, out_H - h_bl, 0),
                            (br_shape, out_H - h_br, out_W - w_br)
                        ]

                        out = np.zeros((out_H, out_W), dtype=int)
                        valid = True

                        for shape, ro, co in placements:
                            h, w = shape.shape
                            for r in range(h):
                                if not valid: break
                                for c in range(w):
                                    if shape[r, c] != 0:
                                        rr, cc = ro + r, co + c
                                        if 0 <= rr < out_H and 0 <= cc < out_W:
                                            if out[rr, cc] != 0:
                                                valid = False
                                                break
                                            out[rr, cc] = int(shape[r, c])
                                        else:
                                            valid = False
                                            break

                        if valid and np.all(out > 0):
                            return out.tolist()

    return [[0]]

